 70→    @Override
 71→    public void onCreate(@Nullable Bundle savedInstanceState) {
 72→        super.onCreate(savedInstanceState);
 73→
 74→        setContentView(R.layout.reader_activity_post_list);
 75→
 76→        OnBackPressedCallback callback = new OnBackPressedCallback(true) {
 77→            @Override
 78→            public void handleOnBackPressed() {
 79→                ReaderPostListFragment fragment = getListFragment();
 80→                if (fragment == null || !fragment.onActivityBackPressed()) {
 81→                    CompatExtensionsKt.onBackPressedCompat(getOnBackPressedDispatcher(), this);
 82→                }
 83→            }
 84→        };
 85→        getOnBackPressedDispatcher().addCallback(this, callback);
 86→
 87→        Toolbar toolbar = findViewById(R.id.toolbar_main);
 88→        setSupportActionBar(toolbar);
 89→        ActionBar actionBar = getSupportActionBar();
 90→        if (actionBar != null) {
 91→            actionBar.setDisplayShowTitleEnabled(true);
 92→            actionBar.setDisplayHomeAsUpEnabled(true);
 93→        }
 94→
 95→        mSource = getIntent().getStringExtra(ReaderConstants.ARG_SOURCE);
 96→        if (getIntent().hasExtra(ReaderConstants.ARG_POST_LIST_TYPE)) {
 97→            mPostListType = (ReaderPostListType) getIntent().getSerializableExtra(ReaderConstants.ARG_POST_LIST_TYPE);
 98→        } else {
 99→            mPostListType = ReaderTypes.DEFAULT_POST_LIST_TYPE;
100→        }
101→
102→        if (getPostListType() == ReaderPostListType.TAG_PREVIEW
103→            || getPostListType() == ReaderPostListType.BLOG_PREVIEW) {
104→            toolbar.setNavigationOnClickListener(view -> finish());
105→
106→            if (getPostListType() == ReaderPostListType.BLOG_PREVIEW) {
107→                setTitle(R.string.reader_title_blog_preview);
108→                if (savedInstanceState == null) {
109→                    long blogId = getIntent().getLongExtra(ReaderConstants.ARG_BLOG_ID, 0);
110→                    long feedId = getIntent().getLongExtra(ReaderConstants.ARG_FEED_ID, 0);
111→                    if (feedId != 0) {
112→                        showListFragmentForFeed(feedId);
113→                        mSiteId = feedId;
114→                    } else {
115→                        showListFragmentForBlog(blogId);
116→                        mSiteId = blogId;
117→                    }
118→                } else {
119→                    mSiteId = savedInstanceState.getLong(ReaderConstants.KEY_SITE_ID);
120→                }
121→            } else if (getPostListType() == ReaderPostListType.TAG_PREVIEW) {
122→                setTitle(R.string.reader_title_tag_preview);
123→                ReaderTag tag = (ReaderTag) getIntent().getSerializableExtra(ReaderConstants.ARG_TAG);
124→                if (tag != null && savedInstanceState == null) {
125→                    showListFragmentForTag(tag, mPostListType);
126→                }
127→            }
128→        }
129→
130→        // restore the activity title
131→        if (savedInstanceState != null && savedInstanceState.containsKey(ReaderConstants.KEY_ACTIVITY_TITLE)) {
132→            setTitle(savedInstanceState.getString(ReaderConstants.KEY_ACTIVITY_TITLE));
133→        }
134→    }
