156→    /*
157→     * This method hides the FilteredRecyclerView toolbar with spinner so to disable content filtering, for reusability
158→     */
159→    private void disableFilteredRecyclerViewToolbar() {
160→        // make it invisible - setting height to zero here because setting visibility to View.GONE wouldn't take the
161→        // occupied space, as otherwise expected
162→        AppBarLayout appBarLayout = findViewById(R.id.app_bar_layout);
163→        if (appBarLayout != null) {
164→            CoordinatorLayout.LayoutParams lp = (CoordinatorLayout.LayoutParams) appBarLayout.getLayoutParams();
165→            lp.height = 0;
166→            appBarLayout.setLayoutParams(lp);
167→        }
168→
169→        // disabling any CoordinatorLayout behavior for scrolling
170→        Toolbar toolbarWithSpinner = findViewById(R.id.toolbar_with_spinner);
171→        if (toolbarWithSpinner != null) {
172→            AppBarLayout.LayoutParams p = (AppBarLayout.LayoutParams) toolbarWithSpinner.getLayoutParams();
173→            p.setScrollFlags(0);
174→            toolbarWithSpinner.setLayoutParams(p);
175→        }
176→    }
