340→                                    public void onClick(View v) {
341→                                        UploadUtils.publishPost(
342→                                                ReaderPostListActivity.this,
343→                                                post,
344→                                                site,
345→                                                mDispatcher
346→                                        );
347→                                    }
348→                                });
349→                    }
350→                }
351→                break;
352→        }
