1991→                            int numPosts;
1992→                            if (mCurrentFeedId != 0) {
1993→                                numPosts = ReaderPostTable.getNumPostsInFeed(mCurrentFeedId);
1994→                            } else {
1995→                                numPosts = ReaderPostTable.getNumPostsInBlog(mCurrentBlogId);
1996→                            }
1997→                            if (numPosts < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
1998→                                updatePostsInCurrentBlogOrFeed(UpdateAction.REQUEST_OLDER);
1999→                                mReaderTracker.track(AnalyticsTracker.Stat.READER_INFINITE_SCROLL);
