2003→                        case SEARCH_RESULTS:
2004→                            ReaderTag searchTag = ReaderUtils.getTagForSearchQuery(mCurrentSearchQuery);
2005→                            int offset = ReaderPostTable.getNumPostsWithTag(searchTag);
2006→                            if (offset < ReaderConstants.READER_MAX_POSTS_TO_DISPLAY) {
2007→                                updatePostsInCurrentSearch(offset);
